patch:
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 93701b2a7791..01ccd456addd 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5702,6 +5702,40 @@ static bool eliminateDeadSwitchCases(SwitchInst *SI, DomTreeUpdater *DTU,
     return true;
   }

+  // Also check if the range of possible values is fully covered by the
+  // explicit cases plus the default destination. This handles cases like
+  // "urem x, N" where the result is in range [0, N) but not all values
+  // have explicit cases.
+  if (HasDefault && DeadCases.empty()) {
+    ConstantRange Range = ConstantRange::fromKnownBits(Known, /*IsSigned=*/false);
+    if (!Range.isEmptySet() && !Range.isFullSet()) {
+      // Check if range_size == num_cases + 1 (all values covered, one to default).
+      // isSizeLargerThan(n) returns true if size > n.
+      // We want: size > num_cases && size <= num_cases + 1
+      // Which is: isSizeLargerThan(num_cases) && !isSizeLargerThan(num_cases + 1)
+      if (Range.isSizeLargerThan(SI->getNumCases()) &&
+          !Range.isSizeLargerThan(SI->getNumCases() + 1)) {
+        // Find the missing case value and add it explicitly.
+        BasicBlock *DefaultDest = SI->getDefaultDest();
+        SmallPtrSet<ConstantInt *, 8> CaseValues;
+        for (const auto &Case : SI->cases())
+          CaseValues.insert(Case.getCaseValue());
+        // Find the value in the range that's not in the explicit cases.
+        // Range is [Min, Max] inclusive (getUnsignedMax returns Max, not Max+1).
+        for (APInt Val = Range.getUnsignedMin();
+             Val.ule(Range.getUnsignedMax()); ++Val) {
+          ConstantInt *CI = ConstantInt::get(SI->getContext(), Val);
+          if (!CaseValues.count(CI)) {
+            SI->addCase(CI, DefaultDest);
+            break;
+          }
+        }
+        createUnreachableSwitchDefault(SI, DTU);
+        return true;
+      }
+    }
+  }
+
   if (DeadCases.empty())
     return false;

